export default async function ({ execution_id }) {
  const r = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/get-status/result');
  const b = await r.json();
  const cmd = (b?.Commands || [])[0] || {};
  const status = (cmd.Status || '').toUpperCase();
  if (['PENDING','INPROGRESS','DELAYED'].includes(status)) {
    throw new Error('Run command still running: ' + status);
  }
  return b;
}
